<?php require_once '../includes/auth.php'; require_login(); require_once '../includes/sentiment.php'; $user=current_user(); if($_SERVER['REQUEST_METHOD']==='POST'){ $event_id=intval($_POST['event_id']); $emoji=$_POST['emoji']??''; $comment=$_POST['comment']??''; $stmt=$pdo->prepare('SELECT id FROM feedback WHERE event_id=? AND user_id=?'); $stmt->execute([$event_id,$user['id']]); if($stmt->fetch()){ $_SESSION['flash']='You already submitted feedback for this event'; header('Location: view_event.php?id='.$event_id); exit; } $res=analyze_sentiment($comment); $label=$res['label']; $score=$res['score']; $stmt=$pdo->prepare('INSERT INTO feedback (event_id,user_id,emoji,comment,sentiment,sentiment_score) VALUES (?,?,?,?,?,?)'); $stmt->execute([$event_id,$user['id'],$emoji,$comment,$label,$score]); $bonus=5 + ($label==='positive'?3:0); $pdo->prepare('UPDATE users SET points = points + ? WHERE id = ?')->execute([$bonus,$user['id']]); $_SESSION['flash']='Feedback submitted'; header('Location: view_event.php?id='.$event_id); exit; } header('Location: index.php'); exit; ?>